#!/usr/bin/env bash
set -euo pipefail

root="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
template="$root/presets/synthv1/Velvet Tines.synthv1"

make_preset() {
  local name="$1"
  shift
  local output="$root/presets/synthv1/$name.synthv1"
  if [[ -e "$output" ]]; then
    printf 'Refusing to replace existing preset: %s\n' "$output" >&2
    exit 1
  fi
  cp "$template" "$output"
  PRESET_NAME="$name" perl -0pi -e 's/(<preset\s+version="[^"]+"\s+name=")[^"]*/$1$ENV{PRESET_NAME}/' "$output"
  local assignment parameter value
  for assignment in "$@"; do
    parameter="${assignment%%=*}"
    value="${assignment#*=}"
    PARAMETER="$parameter" VALUE="$value" perl -0pi -e 's{(<param\s+index="\d+"\s+name="\Q$ENV{PARAMETER}\E">)[^<]*}{$1$ENV{VALUE}}' "$output"
  done
}

